 36	export function installSessionToolResultGuard(
 37	  sessionManager: SessionManager,
 38	  opts?: {
 39	    /**
 40	     * Optional, synchronous transform applied to toolResult messages *before* they are
 41	     * persisted to the session transcript.
 42	     */
 43	    transformToolResultForPersistence?: (
 44	      message: AgentMessage,
 45	      meta: { toolCallId?: string; toolName?: string; isSynthetic?: boolean },
 46	    ) => AgentMessage;
 47	    /**
 48	     * Whether to synthesize missing tool results to satisfy strict providers.
 49	     * Defaults to true.
 50	     */
 51	    allowSyntheticToolResults?: boolean;
 52	  },
 53	): {
 54	  flushPendingToolResults: () => void;
 55	  getPendingIds: () => string[];
 56	} {
 57	  const originalAppend = sessionManager.appendMessage.bind(sessionManager);
 58	  const pending = new Map<string, string | undefined>();
 59	
 60	  const persistToolResult = (
 61	    message: AgentMessage,
 62	    meta: { toolCallId?: string; toolName?: string; isSynthetic?: boolean },
 63	  ) => {
 64	    const transformer = opts?.transformToolResultForPersistence;
 65	    return transformer ? transformer(message, meta) : message;
 66	  };
 67	
 68	  const allowSyntheticToolResults = opts?.allowSyntheticToolResults ?? true;
 69	
 70	  const flushPendingToolResults = () => {
 71	    if (pending.size === 0) return;
 72	    if (allowSyntheticToolResults) {
 73	      for (const [id, name] of pending.entries()) {
 74	        const synthetic = makeMissingToolResult({ toolCallId: id, toolName: name });
 75	        originalAppend(
 76	          persistToolResult(synthetic, {
 77	            toolCallId: id,
 78	            toolName: name,
 79	            isSynthetic: true,
 80	          }) as never,
 81	        );
 82	      }
 83	    }
 84	    pending.clear();
 85	  };
 86	
 87	  const guardedAppend = (message: AgentMessage) => {
 88	    const role = (message as { role?: unknown }).role;
 89	
 90	    if (role === "toolResult") {
 91	      const id = extractToolResultId(message as Extract<AgentMessage, { role: "toolResult" }>);
 92	      const toolName = id ? pending.get(id) : undefined;
 93	      if (id) pending.delete(id);
 94	      return originalAppend(
 95	        persistToolResult(message, {
 96	          toolCallId: id ?? undefined,
 97	          toolName,
 98	          isSynthetic: false,
 99	        }) as never,
100	      );
101	    }
102	
103	    const toolCalls =
104	      role === "assistant"
105	        ? extractAssistantToolCalls(message as Extract<AgentMessage, { role: "assistant" }>)
106	        : [];
107	
108	    if (allowSyntheticToolResults) {
109	      // If previous tool calls are still pending, flush before non-tool results.
110	      if (pending.size > 0 && (toolCalls.length === 0 || role !== "assistant")) {
111	        flushPendingToolResults();
112	      }
113	      // If new tool calls arrive while older ones are pending, flush the old ones first.
114	      if (pending.size > 0 && toolCalls.length > 0) {
115	        flushPendingToolResults();
116	      }
117	    }
118	
119	    const result = originalAppend(message as never);
120	
121	    const sessionFile = (
122	      sessionManager as { getSessionFile?: () => string | null }
123	    ).getSessionFile?.();
124	    if (sessionFile) {
125	      emitSessionTranscriptUpdate(sessionFile);
126	    }
127	
128	    if (toolCalls.length > 0) {
129	      for (const call of toolCalls) {
130	        pending.set(call.id, call.name);
131	      }
132	    }
133	
134	    return result;
135	  };
136	
137	  // Monkey-patch appendMessage with our guarded version.
138	  sessionManager.appendMessage = guardedAppend as SessionManager["appendMessage"];
139	
140	  return {
141	    flushPendingToolResults,
142	    getPendingIds: () => Array.from(pending.keys()),
143	  };
144	}

