 1	import type { SessionManager } from "@mariozechner/pi-coding-agent";
 2	
 3	import { getGlobalHookRunner } from "../plugins/hook-runner-global.js";
 4	import { installSessionToolResultGuard } from "./session-tool-result-guard.js";
 5	
 6	export type GuardedSessionManager = SessionManager & {
 7	  /** Flush any synthetic tool results for pending tool calls. Idempotent. */
 8	  flushPendingToolResults?: () => void;
 9	};
10	
11	/**
12	 * Apply the tool-result guard to a SessionManager exactly once and expose
13	 * a flush method on the instance for easy teardown handling.
14	 */
15	export function guardSessionManager(
16	  sessionManager: SessionManager,
17	  opts?: {
18	    agentId?: string;
19	    sessionKey?: string;
20	    allowSyntheticToolResults?: boolean;
21	  },
22	): GuardedSessionManager {
23	  if (typeof (sessionManager as GuardedSessionManager).flushPendingToolResults === "function") {
24	    return sessionManager as GuardedSessionManager;
25	  }
26	
27	  const hookRunner = getGlobalHookRunner();
28	  const transform = hookRunner?.hasHooks("tool_result_persist")
29	    ? (message: any, meta: { toolCallId?: string; toolName?: string; isSynthetic?: boolean }) => {
30	        const out = hookRunner.runToolResultPersist(
31	          {
32	            toolName: meta.toolName,
33	            toolCallId: meta.toolCallId,
34	            message,
35	            isSynthetic: meta.isSynthetic,
36	          },
37	          {
38	            agentId: opts?.agentId,
39	            sessionKey: opts?.sessionKey,
40	            toolName: meta.toolName,
41	            toolCallId: meta.toolCallId,
42	          },
43	        );
44	        return out?.message ?? message;
45	      }
46	    : undefined;
47	
48	  const guard = installSessionToolResultGuard(sessionManager, {
49	    transformToolResultForPersistence: transform,
50	    allowSyntheticToolResults: opts?.allowSyntheticToolResults,
51	  });
52	  (sessionManager as GuardedSessionManager).flushPendingToolResults = guard.flushPendingToolResults;
53	  return sessionManager as GuardedSessionManager;
54	}

