 79	  if (errorText) replyItems.push({ text: errorText, isError: true });
 80	
 81	  const inlineToolResults =
 82	    params.inlineToolResultsAllowed && params.verboseLevel !== "off" && params.toolMetas.length > 0;
 83	  if (inlineToolResults) {
 84	    for (const { toolName, meta } of params.toolMetas) {
 85	      const agg = formatToolAggregate(toolName, meta ? [meta] : [], {
 86	        markdown: useMarkdown,
 87	      });
 88	      const {
 89	        text: cleanedText,
 90	        mediaUrls,
 91	        audioAsVoice,
 92	        replyToId,
 93	        replyToTag,
 94	        replyToCurrent,
 95	      } = parseReplyDirectives(agg);
 96	      if (cleanedText) {
 97	        replyItems.push({
 98	          text: cleanedText,
 99	          media: mediaUrls,
100	          audioAsVoice,
101	          replyToId,
102	          replyToTag,
103	          replyToCurrent,
104	        });
105	      }
106	    }
107	  }
108	
109	  const reasoningText =
110	    params.lastAssistant && params.reasoningLevel === "on"
111	      ? formatReasoningMessage(extractAssistantThinking(params.lastAssistant))
112	      : "";
113	  if (reasoningText) replyItems.push({ text: reasoningText });
114	
115	  const fallbackAnswerText = params.lastAssistant ? extractAssistantText(params.lastAssistant) : "";
116	  const shouldSuppressRawErrorText = (text: string) => {
117	    if (!lastAssistantErrored) return false;
118	    const trimmed = text.trim();
119	    if (!trimmed) return false;
120	    if (errorText) {
121	      const normalized = normalizeTextForComparison(trimmed);
122	      if (normalized && normalizedErrorText && normalized === normalizedErrorText) return true;
123	      if (trimmed === genericErrorText) return true;
124	    }
125	    if (rawErrorMessage && trimmed === rawErrorMessage) return true;
126	    if (formattedRawErrorMessage && trimmed === formattedRawErrorMessage) return true;
127	    if (normalizedRawErrorText) {
128	      const normalized = normalizeTextForComparison(trimmed);
129	      if (normalized && normalized === normalizedRawErrorText) return true;
130	    }
131	    if (normalizedFormattedRawErrorMessage) {
132	      const normalized = normalizeTextForComparison(trimmed);
133	      if (normalized && normalized === normalizedFormattedRawErrorMessage) return true;
134	    }
135	    if (rawErrorFingerprint) {
136	      const fingerprint = getApiErrorPayloadFingerprint(trimmed);
137	      if (fingerprint && fingerprint === rawErrorFingerprint) return true;
138	    }
139	    return isRawApiErrorPayload(trimmed);
140	  };
141	  const answerTexts = (
142	    params.assistantTexts.length
143	      ? params.assistantTexts
144	      : fallbackAnswerText
145	        ? [fallbackAnswerText]
146	        : []
147	  ).filter((text) => !shouldSuppressRawErrorText(text));
148	
149	  for (const text of answerTexts) {
150	    const {
151	      text: cleanedText,
152	      mediaUrls,
153	      audioAsVoice,
154	      replyToId,
155	      replyToTag,
156	      replyToCurrent,
157	    } = parseReplyDirectives(text);
158	    if (!cleanedText && (!mediaUrls || mediaUrls.length === 0) && !audioAsVoice) {
159	      continue;
160	    }
161	    replyItems.push({
162	      text: cleanedText,
163	      media: mediaUrls,
164	      audioAsVoice,
165	      replyToId,
166	      replyToTag,
167	      replyToCurrent,
168	    });
169	  }
170	
171	  if (params.lastToolError) {
172	    const lastAssistantHasToolCalls =
173	      Array.isArray(params.lastAssistant?.content) &&
174	      params.lastAssistant?.content.some((block) =>
175	        block && typeof block === "object"
176	          ? (block as { type?: unknown }).type === "toolCall"
177	          : false,
178	      );
179	    const lastAssistantWasToolUse = params.lastAssistant?.stopReason === "toolUse";
180	    const hasUserFacingReply =
181	      replyItems.length > 0 && !lastAssistantHasToolCalls && !lastAssistantWasToolUse;
182	    // Check if this is a recoverable/internal tool error that shouldn't be shown to users
183	    // when there's already a user-facing reply (the model should have retried).
184	    const errorLower = (params.lastToolError.error ?? "").toLowerCase();
185	    const isRecoverableError =
186	      errorLower.includes("required") ||
187	      errorLower.includes("missing") ||
188	      errorLower.includes("invalid") ||
189	      errorLower.includes("must be") ||
190	      errorLower.includes("must have") ||
191	      errorLower.includes("needs") ||
192	      errorLower.includes("requires");
193	
194	    // Show tool errors only when:
195	    // 1. There's no user-facing reply AND the error is not recoverable
196	    // Recoverable errors (validation, missing params) are already in the model's context
197	    // and shouldn't be surfaced to users since the model should retry.
198	    if (!hasUserFacingReply && !isRecoverableError) {
199	      const toolSummary = formatToolAggregate(
200	        params.lastToolError.toolName,
201	        params.lastToolError.meta ? [params.lastToolError.meta] : undefined,
202	        { markdown: useMarkdown },
203	      );
204	      const errorSuffix = params.lastToolError.error ? `: ${params.lastToolError.error}` : "";
205	      replyItems.push({
206	        text: `⚠️ ${toolSummary} failed${errorSuffix}`,
207	        isError: true,
208	      });
209	    }
210	  }
211	
212	  const hasAudioAsVoiceTag = replyItems.some((item) => item.audioAsVoice);
213	  return replyItems
214	    .map((item) => ({
215	      text: item.text?.trim() ? item.text.trim() : undefined,
216	      mediaUrls: item.media?.length ? item.media : undefined,
217	      mediaUrl: item.media?.[0],
218	      isError: item.isError,
219	      replyToId: item.replyToId,
220	      replyToTag: item.replyToTag,
221	      replyToCurrent: item.replyToCurrent,
222	      audioAsVoice: item.audioAsVoice || Boolean(hasAudioAsVoiceTag && item.media?.length),
223	    }))
224	    .filter((p) => {
225	      if (!p.text && !p.mediaUrl && (!p.mediaUrls || p.mediaUrls.length === 0)) return false;
226	      if (p.text && isSilentReplyText(p.text, SILENT_REPLY_TOKEN)) return false;
227	      return true;
228	    });
229	}

