 45	export function sanitizeToolResult(result: unknown): unknown {
 46	  if (!result || typeof result !== "object") return result;
 47	  const record = result as Record<string, unknown>;
 48	  const content = Array.isArray(record.content) ? record.content : null;
 49	  if (!content) return record;
 50	  const sanitized = content.map((item) => {
 51	    if (!item || typeof item !== "object") return item;
 52	    const entry = item as Record<string, unknown>;
 53	    const type = typeof entry.type === "string" ? entry.type : undefined;
 54	    if (type === "text" && typeof entry.text === "string") {
 55	      return { ...entry, text: truncateToolText(entry.text) };
 56	    }
 57	    if (type === "image") {
 58	      const data = typeof entry.data === "string" ? entry.data : undefined;
 59	      const bytes = data ? data.length : undefined;
 60	      const cleaned = { ...entry };
 61	      delete cleaned.data;
 62	      return { ...cleaned, bytes, omitted: true };
 63	    }
 64	    return entry;
 65	  });
 66	  return { ...record, content: sanitized };
 67	}
 68	
 69	export function extractToolResultText(result: unknown): string | undefined {
 70	  if (!result || typeof result !== "object") return undefined;
 71	  const record = result as Record<string, unknown>;
 72	  const content = Array.isArray(record.content) ? record.content : null;
 73	  if (!content) return undefined;
 74	  const texts = content
 75	    .map((item) => {
 76	      if (!item || typeof item !== "object") return undefined;
 77	      const entry = item as Record<string, unknown>;
 78	      if (entry.type !== "text" || typeof entry.text !== "string") return undefined;
 79	      const trimmed = entry.text.trim();
 80	      return trimmed ? trimmed : undefined;
 81	    })
 82	    .filter((value): value is string => Boolean(value));
 83	  if (texts.length === 0) return undefined;
 84	  return texts.join("\n");
 85	}
