 30	export async function handleToolExecutionStart(
 31	  ctx: EmbeddedPiSubscribeContext,
 32	  evt: AgentEvent & { toolName: string; toolCallId: string; args: unknown },
 33	) {
 34	  // Flush pending block replies to preserve message boundaries before tool execution.
 35	  ctx.flushBlockReplyBuffer();
 36	  if (ctx.params.onBlockReplyFlush) {
 37	    void ctx.params.onBlockReplyFlush();
 38	  }
 39	
 40	  const rawToolName = String(evt.toolName);
 41	  const toolName = normalizeToolName(rawToolName);
 42	  const toolCallId = String(evt.toolCallId);
 43	  const args = evt.args;
 44	
 45	  if (toolName === "read") {
 46	    const record = args && typeof args === "object" ? (args as Record<string, unknown>) : {};
 47	    const filePath = typeof record.path === "string" ? record.path.trim() : "";
 48	    if (!filePath) {
 49	      const argsPreview = typeof args === "string" ? args.slice(0, 200) : undefined;
 50	      ctx.log.warn(
 51	        `read tool called without path: toolCallId=${toolCallId} argsType=${typeof args}${argsPreview ? ` argsPreview=${argsPreview}` : ""}`,
 52	      );
 53	    }
 54	  }
 55	
 56	  const meta = extendExecMeta(toolName, args, inferToolMetaFromArgs(toolName, args));
 57	  ctx.state.toolMetaById.set(toolCallId, meta);
 58	  ctx.log.debug(
 59	    `embedded run tool start: runId=${ctx.params.runId} tool=${toolName} toolCallId=${toolCallId}`,
 60	  );
 61	
 62	  const shouldEmitToolEvents = ctx.shouldEmitToolResult();
 63	  emitAgentEvent({
 64	    runId: ctx.params.runId,
 65	    stream: "tool",
 66	    data: {
 67	      phase: "start",
 68	      name: toolName,
 69	      toolCallId,
 70	      args: args as Record<string, unknown>,
 71	    },
 72	  });
 73	  // Best-effort typing signal; do not block tool summaries on slow emitters.
 74	  void ctx.params.onAgentEvent?.({
 75	    stream: "tool",
 76	    data: { phase: "start", name: toolName, toolCallId },
 77	  });
 78	
 79	  if (
 80	    ctx.params.onToolResult &&
 81	    shouldEmitToolEvents &&
 82	    !ctx.state.toolSummaryById.has(toolCallId)
 83	  ) {
 84	    ctx.state.toolSummaryById.add(toolCallId);
 85	    ctx.emitToolSummary(toolName, meta);
 86	  }
 87	
 88	  // Track messaging tool sends (pending until confirmed in tool_execution_end).
 89	  if (isMessagingTool(toolName)) {
 90	    const argsRecord = args && typeof args === "object" ? (args as Record<string, unknown>) : {};
 91	    const isMessagingSend = isMessagingToolSendAction(toolName, argsRecord);
 92	    if (isMessagingSend) {
 93	      const sendTarget = extractMessagingToolSend(toolName, argsRecord);
 94	      if (sendTarget) {
 95	        ctx.state.pendingMessagingTargets.set(toolCallId, sendTarget);
 96	      }
 97	      // Field names vary by tool: Discord/Slack use "content", sessions_send uses "message"
 98	      const text = (argsRecord.content as string) ?? (argsRecord.message as string);
 99	      if (text && typeof text === "string") {
100	        ctx.state.pendingMessagingTexts.set(toolCallId, text);
101	        ctx.log.debug(`Tracking pending messaging text: tool=${toolName} len=${text.length}`);
102	      }
103	    }
104	  }
105	}
