 75	    const next = `${candidate.slice(0, MAX_LEN - suffix.length)}${suffix}`;
 76	    if (!params.used.has(next)) return next;
 77	  }
 78	
 79	  const ts = params.mode === "strict" ? `t${Date.now()}` : `_${Date.now()}`;
 80	  return `${candidate.slice(0, MAX_LEN - ts.length)}${ts}`;
 81	}
