138	/**
139	 * Sanitize tool call IDs for provider compatibility.
140	 *
141	 * @param messages - The messages to sanitize
142	 * @param mode - "strict" (alphanumeric only) or "strict9" (alphanumeric length 9)
143	 */
144	export function sanitizeToolCallIdsForCloudCodeAssist(
145	  messages: AgentMessage[],
146	  mode: ToolCallIdMode = "strict",
147	): AgentMessage[] {
148	  // Strict mode: only [a-zA-Z0-9]
149	  // Strict9 mode: only [a-zA-Z0-9], length 9 (Mistral tool call requirement)
150	  // Sanitization can introduce collisions (e.g. `a|b` and `a:b` -> `ab`).
151	  // Fix by applying a stable, transcript-wide mapping and de-duping via suffix.
152	  const map = new Map<string, string>();
153	  const used = new Set<string>();
154	
155	  const resolve = (id: string) => {
156	    const existing = map.get(id);
157	    if (existing) return existing;
158	    const next = makeUniqueToolId({ id, used, mode });
159	    map.set(id, next);
160	    used.add(next);
161	    return next;
162	  };
163	
164	  let changed = false;
165	  const out = messages.map((msg) => {
166	    if (!msg || typeof msg !== "object") return msg;
167	    const role = (msg as { role?: unknown }).role;
168	    if (role === "assistant") {
169	      const next = rewriteAssistantToolCallIds({
170	        message: msg as Extract<AgentMessage, { role: "assistant" }>,
171	        resolve,
