 10	export function agentLoop(prompts, context, config, signal, streamFn) {
 11	    const stream = createAgentStream();
 12	    (async () => {
 13	        const newMessages = [...prompts];
 14	        const currentContext = {
 15	            ...context,
 16	            messages: [...context.messages, ...prompts],
 17	        };
