    const toolResults = [];
    toolResults.push({
        type: "tool_result",
        tool_use_id: msg.toolCallId,
        content: convertContentBlocks(msg.content),
        is_error: msg.isError,
    });
    let j = i + 1;
    while (j < transformedMessages.length && transformedMessages[j].role === "toolResult") {
        const nextMsg = transformedMessages[j];
        toolResults.push({
            type: "tool_result",
            tool_use_id: nextMsg.toolCallId,
            content: convertContentBlocks(nextMsg.content),
            is_error: nextMsg.isError,
        });
        j++;
    }
    i = j - 1;
    params.push({
        role: "user",
        content: toolResults,
    });
}
```

### 2. Where cache_control is added (the bug trigger)

`/c/Users/Administrator/clawdbot/node_modules/.ignored/@mariozechner/pi-ai/dist/providers/anthropic.js`, lines 515-528:
```javascript
